import React from "react";

/* ── Demo placeholder card ─────────────────────────────────────────
   Each card has a visual placeholder area + metadata.
   Replace the placeholder div with a <video>, <iframe>, or <img>.
───────────────────────────────────────────────────────────────────── */
function DemoCard({ tag, title, description, status, isFeature = false }) {
  return (
    <div
      className="card"
      style={{
        padding: "0",
        overflow: "hidden",
        gridColumn: isFeature ? "1 / -1" : undefined
      }}
    >
      {/* Media placeholder — swap this with your video embed or screenshot */}
      <div
        style={{
          background: "#111320",
          border: "none",
          borderBottom: "1px solid #252A40",
          height: isFeature ? "clamp(220px, 35vw, 460px)" : "200px",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          gap: "0.75rem",
          position: "relative"
        }}
      >
        {/* Grid pattern overlay */}
        <div
          aria-hidden="true"
          style={{
            position: "absolute",
            inset: 0,
            backgroundImage:
              "linear-gradient(#252A40 1px, transparent 1px), linear-gradient(90deg, #252A40 1px, transparent 1px)",
            backgroundSize: "40px 40px",
            opacity: 0.18
          }}
        />

        {/* Play icon */}
        <div
          style={{
            width: "56px",
            height: "56px",
            borderRadius: "50%",
            border: "1px solid #252A40",
            background: "#1A1D2E",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1
          }}
        >
          <svg
            width="20"
            height="20"
            viewBox="0 0 24 24"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
          >
            <polygon
              points="5,3 19,12 5,21"
              fill="#5B8DEF"
              opacity="0.8"
            />
          </svg>
        </div>

        <p
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "0.65rem",
            letterSpacing: "0.12em",
            textTransform: "uppercase",
            color: "#3A3A5E",
            zIndex: 1
          }}
        >
          Video demo coming
        </p>
      </div>

      {/* Text content */}
      <div style={{ padding: "1.5rem 1.75rem" }}>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.75rem",
            marginBottom: "0.75rem"
          }}
        >
          <p className="eyebrow">{tag}</p>
          <span
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: "0.6rem",
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: status === "live" ? "#5B8DEF" : "#8A8AB0",
              background:
                status === "live"
                  ? "rgba(91, 141, 239, 0.08)"
                  : "rgba(138, 138, 154, 0.08)",
              border: `1px solid ${status === "live" ? "rgba(91, 141, 239, 0.2)" : "#252A40"}`,
              padding: "0.2rem 0.5rem",
              borderRadius: "0.2rem"
            }}
          >
            {status}
          </span>
        </div>

        <h3
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontWeight: 600,
            fontSize: isFeature ? "1.3rem" : "1.05rem",
            color: "#F0F0EC",
            letterSpacing: "-0.015em",
            marginBottom: "0.6rem"
          }}
        >
          {title}
        </h3>

        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "0.875rem",
            color: "#8A8AB0",
            lineHeight: 1.65,
            maxWidth: "56ch"
          }}
        >
          {description}
        </p>
      </div>
    </div>
  );
}

const demos = [
  {
    tag: "Flagship Build",
    title: "ARIA — Fully Local Agentic AI Assistant",
    description:
      "A completely local AI assistant with real agency: it uses tools, manages tasks, and runs entirely on-device. No cloud, no data leaving the machine. Built to show what agentic AI looks like when privacy is non-negotiable.",
    status: "live",
    isFeature: true
  },
  {
    tag: "Sales Automation",
    title: "ABM Agent: Apollo → HubSpot",
    description:
      "An account-based marketing agent that pulls prospects from Apollo, enriches them, qualifies them against ICP criteria, and pushes structured records to HubSpot — with zero manual steps.",
    status: "live",
    isFeature: false
  },
  {
    tag: "LLM Evaluation",
    title: "LLM-as-Judge Evaluation Framework",
    description:
      "A structured pipeline that uses a language model to evaluate the output of other language models. Prompt design, scoring rubrics, and reproducible test runs — built to catch what vibes-based review misses.",
    status: "live",
    isFeature: false
  },
  {
    tag: "Content System",
    title: "Automated Weekly AI Digest",
    description:
      "Google Apps Script + Gemini API. Curates, summarises, and publishes a weekly AI digest automatically. Runs on a schedule, no human in the loop on delivery.",
    status: "live",
    isFeature: false
  }
];

export default function Demos() {
  const [featured, ...rest] = demos;

  return (
    <section
      id="demos"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40"
      }}
    >
      {/* Header */}
      <div className="mb-14" style={{ maxWidth: "44ch" }}>
        <p className="eyebrow mb-4">Live Demos</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1
          }}
        >
          Things that actually work.
        </h2>
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "1rem",
            color: "#8A8AB0",
            marginTop: "1rem",
            lineHeight: 1.7
          }}
        >
          Video walkthroughs and screenshots of systems in production.
          Not slides, not concepts.
        </p>
      </div>

      {/* Featured demo */}
      <div className="mb-5">
        <DemoCard {...featured} />
      </div>

      {/* Rest of demos */}
      <div
        className="grid gap-5"
        style={{
          gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 300px), 1fr))"
        }}
      >
        {rest.map((demo) => (
          <DemoCard key={demo.title} {...demo} />
        ))}
      </div>

      {/* Footer note */}
      <p
        style={{
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: "0.7rem",
          letterSpacing: "0.08em",
          color: "#3A3A5E",
          marginTop: "2.5rem"
        }}
      >
        // video embeds and screenshots will be added per demo
      </p>
    </section>
  );
}
